class RsGetOrdersServiceImpl:
    def get_rs_orders(self, invoice_num=None, request_type=None):
        if invoice_num is not None and not isinstance(invoice_num, str):
            raise ValueError("invoice_num must be a string")

        if request_type not in ['type1', 'type2', None]:
            raise ValueError("Invalid request_type")

        # Assume orders is a predefined list of orders
        orders = self.fetch_orders()

        if invoice_num:
            orders = [order for order in orders if order['invoice_num'] == invoice_num]

        if request_type:
            orders = [order for order in orders if order['request_type'] == request_type]

        return orders

    def fetch_orders(self):
        # This method would interact with a database or external service
        return [
            {'invoice_num': '123', 'request_type': 'type1'},
            {'invoice_num': '456', 'request_type': 'type2'},
            {'invoice_num': '789', 'request_type': 'type1'},
        ]

