import unittest

class RsGetOrdersServiceImplTest(unittest.TestCase):
    def setUp(self):
        self.service = RsGetOrdersServiceImpl()

    def test_getRsOrders_invoiceNumNotNull_1(self):
        result = self.service.get_rs_orders(invoice_num='123')
        self.assertEqual(len(result), 1)
        self.assertEqual(result[0]['invoice_num'], '123')

    def test_getRsOrders_invoiceNumNotNull_2(self):
        result = self.service.get_rs_orders(invoice_num='456')
        self.assertEqual(len(result), 1)
        self.assertEqual(result[0]['invoice_num'], '456')

    def test_getRsOrders_requestTypeS(self):
        result = self.service.get_rs_orders(request_type='type1')
        self.assertEqual(len(result), 2)

if __name__ == '__main__':
    unittest.main()
